queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasResponsibilities ?child ; p:hasLocations_Managers ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Locations_Managers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?description WHERE {
  ?locations_managers_responsibilities a :Locations_Managers_Responsibilities .
  ?responsibilities a :Responsibilities .
  ?locations_managers_responsibilities p:hasResponsibilities ?responsibilities .
  ?locations_managers a :Locations_Managers .
  ?locations_managers_responsibilities p:hasLocations_Managers ?locations_managers .
  ?locations_managers p:name ?name .
  ?responsibilities p:description ?description .
} }
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasResponsibilities ?child ; p:hasLocations_Managers ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Locations_Managers } }
  FILTER(?nf = ?total)
} }
}
